--
-- Disparadores `user_products`
--
DELIMITER $$
CREATE TRIGGER `restInventario` BEFORE INSERT ON `user_products` FOR EACH ROW UPDATE `products` SET `quantity` = `quantity`-New.quantity WHERE `products`.`code` = New.code
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `restInventarioU` BEFORE UPDATE ON `user_products` FOR EACH ROW UPDATE `products` SET `quantity` = `quantity`-(new.quantity-old.quantity) WHERE `products`.`code` = New.code
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `sumInventario` BEFORE DELETE ON `user_products` FOR EACH ROW UPDATE `products` SET `quantity` = `quantity`+old.quantity WHERE `products`.`code` = old.code
$$
DELIMITER ;

